)

// Version is set at build time
var Version = "dev"

func main() {
	// Check for subcommands before loading full config
	if len(os.Args) > 1 && os.Args[1] == "compact" {
		runCompactSubcommand(os.Args[2:])
		return
	}

	// Load configuration
	cfg, err := config.Load()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to load config: %v\n", err)
		os.Exit(1)
	}

	// Validate TLS configuration before starting
	if err := cfg.Server.ValidateTLS(); err != nil {
		fmt.Fprintf(os.Stderr, "TLS configuration error: %v\n", err)
		os.Exit(1)
	}

	// Setup logger
	logger.Setup(cfg.Log.Level, cfg.Log.Format)
	log.Info().Str("version", Version).Bool("duckdb_arrow", database.ArrowEnabled).Msg("Starting Arc...")

	// Validate Enterprise License early (before component initialization)
	// This allows us to apply core limits to DuckDB and ingestion workers
	var licenseClient *license.Client
	if cfg.License.Key != "" {
		log.Info().
			Str("license_key", cfg.License.Key[:min(12, len(cfg.License.Key))]+"...").
			Str("server_url", license.LicenseServerURL).
			Msg("Validating enterprise license")

		var err error
		licenseClient, err = license.NewClient(&license.ClientConfig{
			LicenseKey: cfg.License.Key,
			Logger:     logger.Get("license"),
		})
		if err != nil {
			log.Warn().Err(err).Msg("Failed to initialize license client - enterprise features disabled")
		} else {
			// Activate or verify license at startup
			lic, err := licenseClient.ActivateOrVerify(context.Background())
			if err != nil {
				log.Warn().
					Err(err).
					Str("license_key", cfg.License.Key[:min(12, len(cfg.License.Key))]+"...").
					Msg("License activation/verification failed - enterprise features disabled")
				licenseClient = nil
			} else {
				log.Info().
					Str("tier", string(lic.Tier)).
					Str("status", lic.Status).
					Int("days_remaining", lic.DaysRemaining).
					Int("max_cores", lic.MaxCores).
					Time("expires_at", lic.ExpiresAt).
					Strs("features", lic.Features).
					Msg("Enterprise license verified successfully")

				// Apply core limits from license to config
				// This ensures DuckDB and ingestion workers respect the license
				if lic.MaxCores > 0 {
					machineCores := runtime.NumCPU()

					if machineCores > lic.MaxCores {
						// Limit Go runtime to licensed cores - this is the real enforcement
						previousGOMAXPROCS := runtime.GOMAXPROCS(lic.MaxCores)
						log.Info().
							Int("machine_cores", machineCores).
							Int("licensed_cores", lic.MaxCores).
							Int("gomaxprocs_before", previousGOMAXPROCS).
							Int("gomaxprocs_after", lic.MaxCores).
							Msg("License core limit applied via GOMAXPROCS")

						// Also set DuckDB thread count to match
						cfg.Database.ThreadCount = lic.MaxCores
						log.Info().
							Int("duckdb_threads", lic.MaxCores).
							Msg("License core limit applied to DuckDB threads")

						// Limit ingestion flush workers to licensed cores
						if cfg.Ingest.FlushWorkers > lic.MaxCores {
							cfg.Ingest.FlushWorkers = lic.MaxCores
							log.Info().
								Int("flush_workers", lic.MaxCores).
								Msg("License core limit applied to ingestion flush workers")
						}
					}
				}
			}
		}
	} else {
		log.Warn().Msg("Enterprise license not configured - enterprise features disabled")
	}

	// If no working license — either none configured, or validation failed
	// above and licenseClient was reset to nil — surface a single invite
	// line so operators on the OSS edition see what they're missing.
	// Deliberately placed after both no-license branches so it fires
	// exactly once regardless of which path got us here.
	if licenseClient == nil {
		log.Info().
			Str("url", "https://basekick.net/enterprise").
			Msg("Running Arc OSS — try Arc Enterprise for tiering, clustering, RBAC, audit, and arcx")
	}

	// Initialize metrics collector
	metrics.Init(logger.Get("metrics"))

	// Initialize timeseries collector with config
	metrics.InitTimeSeriesCollector(
		cfg.Metrics.TimeseriesRetentionMinutes,
		cfg.Metrics.TimeseriesIntervalSeconds,
	)
	log.Info().
		Int("retention_minutes", cfg.Metrics.TimeseriesRetentionMinutes).
		Int("interval_seconds", cfg.Metrics.TimeseriesIntervalSeconds).
		Msg("Timeseries metrics collector initialized")

	// Initialize shutdown coordinator
	shutdownCoordinator := shutdown.New(30*time.Second, logger.Get("shutdown"))

	// arcx (Arc Enterprise DuckDB extension): gate via license before
	// passing the path down to the DB layer. The extension binary is the
	// licensing perimeter, but having Arc refuse to LOAD without a valid
	// license is the operator-friendly behavior.
	arcxPath := cfg.Database.ArcxExtensionPath
	if arcxPath != "" {
		if licenseClient == nil || !licenseClient.CanUseArcx() {
			log.Warn().
				Str("arcx_extension_path", arcxPath).
				Msg("arcx extension configured but license does not include 'arcx' feature — extension will not load")
			arcxPath = ""
		}
	}

	// Initialize DuckDB
	log.Info().
		Int("thread_count", cfg.Database.ThreadCount).
		Int("max_connections", cfg.Database.MaxConnections).
		Str("memory_limit", cfg.Database.MemoryLimit).
		Bool("arcx_enabled", arcxPath != "").
		Int("machine_cpus", runtime.NumCPU()).
		Msg("Initializing DuckDB with database config")
	dbConfig := &database.Config{
		MaxConnections: cfg.Database.MaxConnections,
		MemoryLimit:    cfg.Database.MemoryLimit,
		ThreadCount:    cfg.Database.ThreadCount,
		EnableWAL:      cfg.Database.EnableWAL,
		TempDirectory:  cfg.Database.TempDirectory,
		// S3 configuration for httpfs extension (enables DuckDB to query S3 directly)
		S3Region:    cfg.Storage.S3Region,
		S3AccessKey: cfg.Storage.S3AccessKey,
		S3SecretKey: cfg.Storage.S3SecretKey,
		S3Endpoint:  cfg.Storage.S3Endpoint,
		S3UseSSL:    cfg.Storage.S3UseSSL,
		S3PathStyle: cfg.Storage.S3PathStyle,
		// Azure Blob Storage configuration for azure extension
		AzureAccountName: cfg.Storage.AzureAccountName,
		AzureAccountKey:  cfg.Storage.AzureAccountKey,
		AzureEndpoint:    cfg.Storage.AzureEndpoint,
		// Query optimization
		EnableS3Cache:     cfg.Query.EnableS3Cache,
		S3CacheSize:       cfg.Query.S3CacheSize,
		S3CacheTTLSeconds: cfg.Query.S3CacheTTLSeconds,
		// arcx loader (cleared above when license does not permit)
		ArcxExtensionPath: arcxPath,
		// arcx storage root for the partition_agg table function. Only set
		// when the loader is enabled; the DB layer ignores it otherwise.
		ArcxStorageRoot: func() string {
			if arcxPath == "" {
				return ""
			}
			return cfg.Storage.LocalPath
		}(),
	}

	// Resolve temp_directory to an absolute path so the value DuckDB stores
	// internally and the path the sweep walks are the same regardless of
	// the process CWD (matters for systemd units with WorkingDirectory=/
	// and for docker entrypoints rooted at /). Falls back to the
	// configured value if Abs fails. Normalize to forward slashes so the
	// path is safe to interpolate into a DuckDB SQL string on Windows
	// (backslashes would become escape sequences if standard_conforming_
	// strings is ever disabled) and so the SQL value matches the sweep
	// path byte-for-byte. Matches the pattern used by ArcxExtensionPath.
	if dbConfig.TempDirectory != "" {
		if abs, err := filepath.Abs(dbConfig.TempDirectory); err == nil {
			dbConfig.TempDirectory = abs
		}
		dbConfig.TempDirectory = filepath.ToSlash(dbConfig.TempDirectory)
	}

	// Sweep orphaned DuckDB spill files from a previous run (kill -9,
	// OOM-kill, crash). DuckDB unlinks these on graceful close, but
	// otherwise they survive and accumulate. Runs BEFORE database.New so
	// we never race with our own DuckDB process. Files younger than
	// spillFileLiveThreshold are skipped to protect any concurrent arc;
	// the durable invariant is "no two arc instances share a
	// temp_directory" — document this in the operator config.
	if err := database.CleanupOrphanedSpillFiles(dbConfig.TempDirectory, logger.Get("database")); err != nil {
		log.Warn().Err(err).Msg("Failed to sweep orphaned DuckDB spill files; continuing")
	}

	db, err := database.New(dbConfig, logger.Get("database"))
	if err != nil {
		log.Fatal().Err(err).Msg("Failed to initialize database")
	}
	shutdownCoordinator.Register("database", db, shutdown.PriorityDatabase)

	// Test query
	log.Info().Msg("Testing DuckDB connection...")
	rows, err := db.Query("SELECT 'Hello from Arc in Go!' as message, version() as duckdb_version")
	if err != nil {
		log.Fatal().Err(err).Msg("Failed to execute test query")
	}
	defer rows.Close()

	var message, version string
	if rows.Next() {
		if err := rows.Scan(&message, &version); err != nil {
			log.Fatal().Err(err).Msg("Failed to scan result")
		}
		log.Info().
			Str("message", message).
			Str("duckdb_version", version).
			Msg("Test query successful")
	}

	// Print database stats
	stats := db.Stats()
	log.Info().
		Int("max_open", stats.MaxOpenConnections).
		Int("open", stats.OpenConnections).
		Int("in_use", stats.InUse).

package database

import (
	"context"
	"database/sql"
	"database/sql/driver"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"runtime"
	"strings"
	"sync"
	"time"

	"github.com/basekick-labs/arc/internal/memtrim"
	duckdb "github.com/duckdb/duckdb-go/v2"
	"github.com/rs/zerolog"
)

// ArrowEnabled is set to true by duckdb_arrow.go init() when compiled with the duckdb_arrow tag.
var ArrowEnabled bool

// QueryProfile contains timing breakdown for a query execution
type QueryProfile struct {
	TotalMs     float64 `json:"total_ms"`
	PlannerMs   float64 `json:"planner_ms"`
	ExecutionMs float64 `json:"execution_ms"`
	RowsScanned uint64  `json:"rows_scanned"`
	Latency     float64 `json:"latency_ms"` // DuckDB reported latency
}

// DuckDB manages DuckDB connections and query execution
// Note: No mutex is needed here because:
// 1. *sql.DB maintains its own connection pool with internal synchronization
// 2. DuckDB handles concurrent queries internally
// 3. Adding a mutex would only add overhead without safety benefits
type DuckDB struct {
	db     *sql.DB
	logger zerolog.Logger
	config *Config
}

// escapeSQLString escapes single quotes for safe use in DuckDB SQL strings.
// This prevents SQL injection when interpolating configuration values.
func escapeSQLString(s string) string {
	return strings.ReplaceAll(s, "'", "''")
}

// stripURLScheme normalises an S3 endpoint into the bare "host:port" form
// that DuckDB's httpfs extension expects. The AWS SDK accepts either
// "host:port" or "scheme://host:port[/]"; DuckDB does not. Passing scheme'd
// or trailing-slashed input through verbatim produces "http://http://..."
// URLs that fail to resolve.
//
// Strips, in order:
//  - leading and trailing whitespace (paste artefacts),
//  - leading "http://" or "https://" (case-insensitive — RFC 3986 schemes
//    are case-insensitive and users routinely paste mixed-case),
//  - trailing slashes ("host:port/" → "host:port").
//
// The case of the remainder is preserved (bucket names and path components
// can be case-sensitive depending on the S3 implementation).
func stripURLScheme(endpoint string) string {
	endpoint = strings.TrimSpace(endpoint)
	lower := strings.ToLower(endpoint)
	switch {
	case strings.HasPrefix(lower, "https://"):
		endpoint = endpoint[len("https://"):]
	case strings.HasPrefix(lower, "http://"):
		endpoint = endpoint[len("http://"):]
	}
	return strings.TrimRight(endpoint, "/")
}

// Config holds DuckDB configuration
type Config struct {
	MaxConnections int
	MemoryLimit    string
	ThreadCount    int
	EnableWAL      bool
	// TempDirectory is where DuckDB writes query spill files (HASH_GROUP_BY
	// overflow, large sorts, joins). Empty leaves DuckDB's default
	// (CWD-relative). Orphans from a crashed previous run are swept by
	// CleanupOrphanedSpillFiles at startup.
	TempDirectory string
	// S3 configuration for httpfs extension
	S3Region    string
	S3AccessKey string
	S3SecretKey string
	S3Endpoint  string // Custom endpoint for MinIO or S3-compatible services
	S3UseSSL    bool
	S3PathStyle bool // Use path-style addressing (required for MinIO)
	// Azure Blob Storage configuration for azure extension
	AzureAccountName string
	AzureAccountKey  string
	AzureEndpoint    string // Custom endpoint (optional)
	// Query optimization configuration
	EnableS3Cache     bool  // Enable S3 file caching via cache_httpfs extension
	S3CacheSize       int64 // Cache size in bytes
	S3CacheTTLSeconds int   // Cache entry TTL in seconds (default: 3600)
	// ArcxExtensionPath is the absolute path to arcx.duckdb_extension.
	// Empty disables the loader. Arc Enterprise only — the caller
	// (cmd/arc/main.go) clears this field when the license does not
	// permit arcx, so the DB layer trusts presence.
	ArcxExtensionPath string
	// ArcxStorageRoot is the filesystem root arcx's arc_partition_agg
	// table function uses to locate parquet files. Set to the local
	// storage backend's root path; ignored when ArcxExtensionPath is empty.
	ArcxStorageRoot string
}

// New creates a new DuckDB instance
func New(cfg *Config, logger zerolog.Logger) (*DuckDB, error) {
	dsn := buildDSN(cfg)

	// Open the *sql.DB. When arcx is configured we route through
	// duckdb.NewConnector + connInitFn so the LOAD runs on every pooled
	// connection (DuckDB's LOAD is per-connection — there is no SET GLOBAL
	// equivalent, so a bare `db.Exec("LOAD …")` would only register the
	// extension on whichever pool member database/sql happened to hand us).
	db, err := openDuckDB(dsn, cfg, logger)
	if err != nil {
		return nil, fmt.Errorf("failed to open duckdb: %w", err)
	}

	// Set connection pool limits optimized for query-heavy workloads
	db.SetMaxOpenConns(cfg.MaxConnections)
	db.SetMaxIdleConns(cfg.MaxConnections)  // Keep all connections idle-ready to avoid acquisition overhead
	db.SetConnMaxLifetime(0)                // No lifetime limit - DuckDB handles connection health internally
	db.SetConnMaxIdleTime(10 * time.Minute) // Longer idle time to reduce connection churn

	// Test connection
	if err := db.Ping(); err != nil {
		db.Close()
		return nil, fmt.Errorf("failed to ping duckdb: %w", err)
	}

	// Configure database settings (memory limit, threads)
	if err := configureDatabase(db, cfg, logger); err != nil {
		db.Close()
		return nil, fmt.Errorf("failed to configure duckdb: %w", err)
	}

	s3Enabled := cfg.S3AccessKey != "" && cfg.S3SecretKey != ""
	azureEnabled := cfg.AzureAccountName != "" && cfg.AzureAccountKey != ""
	logger.Info().
		Int("max_connections", cfg.MaxConnections).
		Str("memory_limit", cfg.MemoryLimit).
		Int("thread_count", cfg.ThreadCount).
		Bool("wal_enabled", cfg.EnableWAL).
		Bool("s3_enabled", s3Enabled).
		Str("s3_region", cfg.S3Region).
		Bool("s3_cache_enabled", cfg.EnableS3Cache).
		Bool("azure_enabled", azureEnabled).
		Str("azure_account", cfg.AzureAccountName).
		Msg("DuckDB initialized")

	return &DuckDB{
		db:     db,
		logger: logger,
		config: cfg,
	}, nil
}

// buildDSN constructs the DuckDB connection string
// NOTE: DuckDB memory_limit and threads must be set via SET commands after connection
func buildDSN(cfg *Config) string {
	// Loading arcx (or any unsigned extension) requires the DuckDB
	// allow_unsigned_extensions flag at connection time — it cannot be
	// flipped via SET after the connection is open. We pass it via the
	// duckdb-go driver's DSN query-string. When arcx is disabled, return
	// the empty DSN (in-memory database, default settings).
	if cfg.ArcxExtensionPath != "" {
		return "?allow_unsigned_extensions=true"
	}
	return ""
}

// openDuckDB returns a *sql.DB. When arcx is configured we go through
// duckdb.NewConnector with an init callback that runs `LOAD '…'` on every
// new pooled connection — DuckDB's LOAD is per-connection, so this is the
// only correct way to make arcx available across the whole pool. When
// arcx is disabled we use the simpler driver-registered sql.Open path.
func openDuckDB(dsn string, cfg *Config, logger zerolog.Logger) (*sql.DB, error) {
	if cfg.ArcxExtensionPath == "" {
		return sql.Open("duckdb", dsn)
	}

	// Capture the path into a local so the closure does not retain the
	// whole *Config (the logger field below would otherwise pull cfg in
	// for its entire lifetime — gemini round 1).
	//
	// filepath.ToSlash normalises Windows-style backslashes to forward
	// slashes. DuckDB's LOAD parses the path as a single-quoted SQL
	// string literal, where backslashes are not interpreted as escapes
	// but Windows paths like `C:\Program Files\arcx\arcx.duckdb_extension`
	// have been observed to confuse the loader on some Windows builds.
	// Forward slashes are accepted on every platform DuckDB supports.
	path := filepath.ToSlash(cfg.ArcxExtensionPath)
	loadSQL := fmt.Sprintf("LOAD '%s'", escapeSQLString(path))
	// Set arcx.storage_root in the same connInitFn so the operator can
	// resolve filesystem paths without taking them as arguments. The setting
	// is registered by the extension at LOAD time; SET runs in the same
	// statement after LOAD via a semicolon separator.
	connInitSQL := loadSQL
	if cfg.ArcxStorageRoot != "" {
		storageRoot := filepath.ToSlash(cfg.ArcxStorageRoot)
		connInitSQL = fmt.Sprintf("%s; SET arcx.storage_root = '%s'", loadSQL, escapeSQLString(storageRoot))
	}
	componentLogger := logger.With().Str("component", "duckdb").Logger()

	// arcxLoadTimeout bounds the connection-init LOAD so a corrupt or
	// network-mounted extension file cannot hang pool acquisition
	// indefinitely. 30s is generous for dlopen + DuckDB's Load() hook;
	// real loads are tens of milliseconds.
	const arcxLoadTimeout = 30 * time.Second

	// loadErrLogOnce gates the Error log to once per process. The error
	// itself still propagates to database/sql on every connInitFn call —
	// only the log line is throttled. Without this, a misconfigured path
	// (missing file, ABI mismatch) under load would emit one Error per
	// connection-acquire attempt — easily hundreds per second.
	var loadErrLogOnce sync.Once

	connector, err := duckdb.NewConnector(dsn, func(execer driver.ExecerContext) error {
		ctx, cancel := context.WithTimeout(context.Background(), arcxLoadTimeout)
		defer cancel()
		_, execErr := execer.ExecContext(ctx, connInitSQL, nil)
		if execErr != nil {
			loadErrLogOnce.Do(func() {
				componentLogger.Error().Err(execErr).
					Str("path", path).
					Msg("arcx LOAD failed on new DuckDB connection (subsequent failures suppressed for log hygiene)")
			})
			return fmt.Errorf("arcx LOAD on new connection: %w", execErr)
		}
		return nil
	})
	if err != nil {
		return nil, fmt.Errorf("create duckdb connector for arcx: %w", err)
	}
	return sql.OpenDB(connector), nil
}

// configureDatabase sets DuckDB configuration after connection
func configureDatabase(db *sql.DB, cfg *Config, logger zerolog.Logger) error {
	// Set memory limit to prevent unbounded memory growth
	if cfg.MemoryLimit != "" {
		if _, err := db.Exec(fmt.Sprintf("SET GLOBAL memory_limit='%s'", escapeSQLString(cfg.MemoryLimit))); err != nil {
			return fmt.Errorf("failed to set memory_limit: %w", err)
		}
	}
	// Set thread count
	if cfg.ThreadCount > 0 {
		logger.Info().Int("threads", cfg.ThreadCount).Msg("Setting DuckDB thread count")
		if _, err := db.Exec(fmt.Sprintf("SET GLOBAL threads=%d", cfg.ThreadCount)); err != nil {
			return fmt.Errorf("failed to set threads: %w", err)
		}
	}
	// Pin DuckDB's spill location so operators can place it on fast scratch
	// storage AND so CleanupOrphanedSpillFiles can sweep a known path at
	// startup. Empty leaves DuckDB's default (CWD-relative). The directory
	// must exist before DuckDB tries to write a spill file; create it with
	// 0o700 so intermediate query state is not world-readable on shared
	// hosts. escapeSQLString is sufficient defense against the path
	// reaching DuckDB's parser because Arc relies on DuckDB's default
	// standard_conforming_strings=on (single-quote doubling is the only
	// in-band escape).
	if cfg.TempDirectory != "" {
		if err := os.MkdirAll(cfg.TempDirectory, 0o700); err != nil {
			return fmt.Errorf("failed to create temp_directory %q: %w", cfg.TempDirectory, err)
		}
		logger.Info().Str("temp_directory", cfg.TempDirectory).Msg("Setting DuckDB temp directory")
		if _, err := db.Exec(fmt.Sprintf("SET GLOBAL temp_directory='%s'", escapeSQLString(cfg.TempDirectory))); err != nil {
			return fmt.Errorf("failed to set temp_directory: %w", err)
		}
	}

	// Cache Parquet file metadata (schema, row group info) to reduce I/O on repeated access
	if _, err := db.Exec("SET GLOBAL parquet_metadata_cache=true"); err != nil {
		logger.Warn().Err(err).Msg("Failed to enable parquet metadata cache (continuing without it)")
	}

	// Preserve insertion order for deterministic results (important for LIMIT queries)
	if _, err := db.Exec("SET GLOBAL preserve_insertion_order=true"); err != nil {
		logger.Warn().Err(err).Msg("Failed to set preserve_insertion_order")
	}

	// Configure httpfs extension for S3 access if credentials are provided
	if cfg.S3AccessKey != "" && cfg.S3SecretKey != "" {
		if err := configureS3Access(db, cfg, logger); err != nil {
			return fmt.Errorf("failed to configure S3 access: %w", err)
		}
	}

	// Configure azure extension for Azure Blob Storage access if credentials are provided
	if cfg.AzureAccountName != "" && cfg.AzureAccountKey != "" {
		if err := configureAzureAccess(db, cfg, logger); err != nil {
			return fmt.Errorf("failed to configure Azure access: %w", err)
		}
	}

	// Verify the proprietary arcx extension is loaded into the pool. The
	// LOAD itself happens inside the connInitFn registered with
	// duckdb.NewConnector (see openDuckDB) — that callback fires on every
	// new pool connection so the extension is available across the whole
	// pool, not just the connection that happened to receive the first
	// db.Exec("LOAD …") call. Here we pin one connection and ask it for
	// arcx_version() to confirm the load actually took effect. License
	// gating happens upstream (cmd/arc/main.go clears ArcxExtensionPath
	// when the license does not permit it), so an empty path means arcx
	// is intentionally disabled.
	if cfg.ArcxExtensionPath != "" {
		if err := verifyArcxLoaded(db, cfg, logger); err != nil {
			return fmt.Errorf("failed to verify arcx extension: %w", err)
		}
	}

	return nil
}

// verifyArcxLoaded confirms the proprietary arcx DuckDB extension is
// available on a pool connection. The LOAD itself runs in the connInitFn
// registered with duckdb.NewConnector for every new connection; this
// function only proves that one of those connections actually responded
// to arcx_version(). An empty version string signals an ABI mismatch or
// a buggy build of arcx — fail-fast rather than limping along.
//
// Pinned via db.Conn(ctx) so the verify query lands on a connection
// that has gone through the init callback (any connection from the
// pool would, but pinning is defensive against future driver changes).
func verifyArcxLoaded(db *sql.DB, cfg *Config, logger zerolog.Logger) error {
	if cfg.ArcxExtensionPath == "" {
		return nil // belt-and-suspenders; caller already guards this
	}
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	conn, err := db.Conn(ctx)
	if err != nil {
		return fmt.Errorf("acquire pinned connection: %w", err)
	}
	defer conn.Close()

	var ver string
	if err := conn.QueryRowContext(ctx, "SELECT arcx_version()").Scan(&ver); err != nil {
		return fmt.Errorf("arcx_version() proof-of-life: %w", err)
	}
	if strings.TrimSpace(ver) == "" {
		return fmt.Errorf("arcx_version() returned empty string (extension binary corrupt or ABI mismatch?)")
	}
	logger.Info().
		Str("component", "duckdb").
		Str("path", cfg.ArcxExtensionPath).
		Str("arcx_version", ver).
		Msg("arcx extension loaded")
	return nil
}

// configureS3Access sets up the httpfs extension for S3 access
// Note: We use SET GLOBAL to ensure settings persist across all connections in the pool
func configureS3Access(db *sql.DB, cfg *Config, logger zerolog.Logger) error {
	// Install and load the httpfs extension
	if _, err := db.Exec("INSTALL httpfs"); err != nil {
		return fmt.Errorf("failed to install httpfs: %w", err)
	}
	if _, err := db.Exec("LOAD httpfs"); err != nil {
		return fmt.Errorf("failed to load httpfs: %w", err)
	}

	// Set S3 credentials using GLOBAL scope to persist across connections
	// Note: credentials are escaped to prevent SQL injection
	if _, err := db.Exec(fmt.Sprintf("SET GLOBAL s3_access_key_id='%s'", escapeSQLString(cfg.S3AccessKey))); err != nil {
		return fmt.Errorf("failed to set s3_access_key_id: %w", err)
	}
	if _, err := db.Exec(fmt.Sprintf("SET GLOBAL s3_secret_access_key='%s'", escapeSQLString(cfg.S3SecretKey))); err != nil {
		return fmt.Errorf("failed to set s3_secret_access_key: %w", err)
	}

	// Set S3 region
	if cfg.S3Region != "" {
		if _, err := db.Exec(fmt.Sprintf("SET GLOBAL s3_region='%s'", escapeSQLString(cfg.S3Region))); err != nil {
			return fmt.Errorf("failed to set s3_region: %w", err)
		}
	}

	// Set custom endpoint for MinIO or S3-compatible services
	if cfg.S3Endpoint != "" {
		if _, err := db.Exec(fmt.Sprintf("SET GLOBAL s3_endpoint='%s'", escapeSQLString(stripURLScheme(cfg.S3Endpoint)))); err != nil {
}

// QueryWithProfile executes a query and returns timing breakdown using DuckDB profiling
// This is used to measure parsing/planning overhead for optimization decisions
//
// The caller MUST close both resources when done:
//  1. rows.Close() — releases the result set
//  2. conn.Close() — returns the pinned connection to the pool
func (d *DuckDB) QueryWithProfile(query string) (*sql.Rows, *sql.Conn, *QueryProfile, error) {
	return d.QueryWithProfileContext(context.Background(), query)
}

// QueryWithProfileContext executes a query with context support for timeout/cancellation
// and returns timing breakdown using DuckDB profiling.
// All profiling PRAGMAs and the query are pinned to a single connection to avoid
// race conditions across the connection pool.
//
// The caller MUST close both resources when done:
//  1. rows.Close() — releases the result set
//  2. conn.Close() — returns the pinned connection to the pool
func (d *DuckDB) QueryWithProfileContext(ctx context.Context, query string) (*sql.Rows, *sql.Conn, *QueryProfile, error) {
	conn, err := d.db.Conn(ctx)
	if err != nil {
		return nil, nil, nil, fmt.Errorf("failed to acquire connection: %w", err)
	}

	// Create a temporary file for profiling output
	tmpFile, err := os.CreateTemp("", "duckdb_profile_*.json")
	if err != nil {
		// Fall back to regular query if we can't create temp file
		rows, err := conn.QueryContext(ctx, query)
		if err != nil {
			conn.Close()
			return nil, nil, nil, err
		}
		return rows, conn, nil, nil
	}
	profilePath := tmpFile.Name()
	tmpFile.Close()
	defer os.Remove(profilePath)

	// Enable JSON profiling with custom metrics to capture planning time
	// All PRAGMAs run on the same pinned connection
	if _, err := conn.ExecContext(ctx, "PRAGMA enable_profiling='json'"); err != nil {
		d.logger.Warn().Err(err).Msg("Failed to enable profiling")
	}
	if _, err := conn.ExecContext(ctx, fmt.Sprintf("PRAGMA profiling_output='%s'", profilePath)); err != nil {
		d.logger.Warn().Err(err).Msg("Failed to set profiling output")
	}
	// Enable planner timing metrics
	if _, err := conn.ExecContext(ctx, "SET custom_profiling_settings='{\"PLANNER\": \"true\", \"PLANNER_BINDING\": \"true\", \"PHYSICAL_PLANNER\": \"true\", \"OPERATOR_TIMING\": \"true\", \"OPERATOR_CARDINALITY\": \"true\"}'"); err != nil {
		d.logger.Warn().Err(err).Msg("Failed to set custom profiling settings")
	}

	// Execute the query with timing and context on the pinned connection
	start := time.Now()
	rows, err := conn.QueryContext(ctx, query)
	totalTime := time.Since(start)

	// Disable profiling on the same connection
	conn.ExecContext(ctx, "PRAGMA disable_profiling")

